const rows = $('Read price_entries').all().map(i => i.json);

const entries = rows
  .filter(r => String(r.commodity || '').toLowerCase().trim() === 'maize')
  .map(r => ({
    location: r.location || '',
    price: parseFloat(r.price),
    price_unit: r.price_unit || 'per bag',
    source_type: r.source_type || 'unknown',
    source_name: r.source_name || '',
    observed_date: r.observed_date || '',
    confidence: (r.confidence || 'low')
  }))
  .filter(e => !isNaN(e.price) && e.price > 0);

const count = entries.length;
const location_scope = 'Kaduna State (sample)';
const retrieval_query = 'maize farmgate and market price, Kaduna State area, recent months and lean season, 100kg bag price and outlook';

// Source breakdown
const source_breakdown = {};
entries.forEach(e => { source_breakdown[e.source_type] = (source_breakdown[e.source_type] || 0) + 1; });
const source_list = Object.keys(source_breakdown).map(k => k + ' (' + source_breakdown[k] + ')').join(', ');

// Insufficient-data guard: refuse to summarize prices when too few entries
if (count < 3) {
  const parts = [];
  parts.push('You are writing a maize price note for a farmer cooperative in Kaduna State.');
  parts.push('There are only ' + count + ' usable maize price entries available. This is INSUFFICIENT to summarize the market reliably.');
  parts.push('Write 1-2 plain sentences stating there is not enough recent price data to give a reliable summary, and that more entries are needed before negotiation guidance.');
  parts.push('Do NOT invent, estimate, or state any specific price or price range as reliable.');
  parts.push('Return ONLY a JSON object, no markdown fences:');
  parts.push('{ "summary_text": "<the note>", "data_confidence": "insufficient", "mentions_outliers": false }');
  return [{ json: {
    insufficient_data: true,
    count: count,
    commodity: 'maize',
    location_scope: location_scope,
    stats: null,
    outliers: [],
    source_breakdown: source_breakdown,
    source_list: source_list,
    data_confidence: 'insufficient',
    retrieval_query: retrieval_query,
    prompt: parts.join('\n')
  }}];
}

const prices = entries.map(e => e.price).sort((a, b) => a - b);
const min = prices[0];
const max = prices[prices.length - 1];
const mid = Math.floor(prices.length / 2);
const median = prices.length % 2 === 0 ? Math.round((prices[mid - 1] + prices[mid]) / 2) : prices[mid];
const mean = Math.round(prices.reduce((a, b) => a + b, 0) / prices.length);

// Outlier rule (rule-based thresholds): outside +/-25% of median, or outside the sane band 30000-80000
const lowerBound = Math.round(median * 0.75);
const upperBound = Math.round(median * 1.25);
const outliers = entries.filter(e =>
  e.price < lowerBound || e.price > upperBound || e.price < 30000 || e.price > 80000
).map(e => ({
  price: e.price,
  source_type: e.source_type,
  source_name: e.source_name,
  direction: (e.price > upperBound || e.price > 80000) ? 'above range' : 'below range'
}));

// Rule-based data confidence: based on volume, then downgraded if sources are weak
let data_confidence;
if (count < 6) data_confidence = 'low';
else if (count < 10) data_confidence = 'medium';
else data_confidence = 'high';
const weak = entries.filter(e => e.confidence === 'low' || e.source_type === 'sample' || e.source_type === 'public_report').length;
if (weak / count > 0.4) {
  if (data_confidence === 'high') data_confidence = 'medium';
  else if (data_confidence === 'medium') data_confidence = 'low';
}

const stats = { count, min, max, median, mean, lowerBound, upperBound };
const priceUnit = entries[0].price_unit || 'per bag';

const parts = [];
parts.push('You are writing a short farmgate maize price summary for a Nigerian farmer cooperative in Kaduna State.');
parts.push('Use ONLY the figures provided below. Do NOT invent, estimate, forecast, or use any number that is not given here.');
parts.push('If you are unsure, say the data is limited rather than guessing.');
parts.push('');
parts.push('DATA (all values in Naira, ' + priceUnit + '):');
parts.push('Commodity: maize');
parts.push('Location scope: ' + location_scope);
parts.push('Number of price entries: ' + count);
parts.push('Lowest: ' + min);
parts.push('Highest: ' + max);
parts.push('Median: ' + median);
parts.push('Source types present: ' + source_list);
parts.push('Computed data confidence: ' + data_confidence);
if (outliers.length) {
  parts.push('Outliers flagged (outside +/-25% of median or outside 30000-80000):');
  outliers.forEach(o => parts.push('  - NGN ' + o.price + ' (' + o.direction + ') from ' + o.source_name + ' [' + o.source_type + ']'));
} else {
  parts.push('Outliers flagged: none');
}
parts.push('');
parts.push('Write the summary as 2-4 plain sentences a farmer can understand. You MUST:');
parts.push('1. State the price range (lowest to highest) and the median.');
parts.push('2. Mention how many entries this is based on and the source types.');
parts.push('3. If any outliers were flagged, note that they should be reviewed before negotiation.');
parts.push('4. End with the data confidence level (' + data_confidence + ') and the reason (number of entries and source mix).');
parts.push('Do not add a greeting or signature.');
parts.push('');
parts.push('Return ONLY a JSON object, no markdown fences:');
parts.push('{ "summary_text": "<the summary>", "data_confidence": "' + data_confidence + '", "mentions_outliers": ' + (outliers.length > 0 ? 'true' : 'false') + ' }');

return [{ json: {
  insufficient_data: false,
  count: count,
  commodity: 'maize',
  location_scope: location_scope,
  stats: stats,
  outliers: outliers,
  source_breakdown: source_breakdown,
  source_list: source_list,
  data_confidence: data_confidence,
  retrieval_query: retrieval_query,
  prompt: parts.join('\n')
}}];

const stats = $('Compute price stats & outliers').all()[0].json;
const retrieved = $('Retrieve market context').all().map((it) => {
  const d = it.json.document || it.json;
  return { text: String(d.pageContent || d.text || '').trim(), meta: d.metadata || d.meta || {} };
}).filter((r) => r.text);

const parts = [];
parts.push('You are writing a short farmgate maize price summary for a Nigerian farmer cooperative in Kaduna State (the Kaduna Maize Farmers Cooperative).');
parts.push('You have TWO kinds of input: (A) price numbers the cooperative computed from its own records, and (B) retrieved public market-intelligence passages for context.');
parts.push('RULES:');
parts.push('- The numbers in (A) are the only authoritative figures for this cooperative. Do NOT change them.');
parts.push('- Do NOT invent prices. You may cite figures from the retrieved passages (B) ONLY to give context, and you MUST attribute each such figure to its source.');
parts.push('- If the retrieved passages are empty or not relevant, say plainly that no external market context was available and rely only on the numbers in (A).');
parts.push('- The bag unit is a 100kg bag.');
parts.push('');
parts.push('(A) COOPERATIVE OWN DATA (Naira per 100kg bag):');
if (stats.insufficient_data) {
  parts.push('Only ' + stats.count + ' usable maize price entries - INSUFFICIENT to state a reliable range. Do not invent one.');
} else {
  const s = stats.stats;
  parts.push('Entries: ' + stats.count + ' | Lowest: ' + s.min + ' | Highest: ' + s.max + ' | Median: ' + s.median);
  parts.push('Source types: ' + stats.source_list);
  parts.push('Computed data confidence: ' + stats.data_confidence);
  if ((stats.outliers || []).length) {
    parts.push('Outliers flagged:');
    stats.outliers.forEach((o) => parts.push('  - NGN ' + o.price + ' (' + o.direction + ') from ' + o.source_name + ' [' + o.source_type + ']'));
  } else {
    parts.push('Outliers flagged: none');
  }
}
parts.push('');
parts.push('(B) RETRIEVED MARKET CONTEXT (public sources; cite by source):');
if (retrieved.length) {
  retrieved.forEach((r, i) => {
    parts.push('[' + (i + 1) + '] source: ' + (r.meta.source || 'unknown') + (r.meta.period ? ' (' + r.meta.period + ')' : ''));
    parts.push(r.text);
    parts.push('');
  });
} else {
  parts.push('(none retrieved)');
  parts.push('');
}
parts.push('WRITE the summary as 2-4 plain sentences a farmer can understand. You MUST:');
if (stats.insufficient_data) {
  parts.push('1. State that the cooperative does not have enough recent price entries to give a reliable range, and do not invent one.');
  parts.push('2. You MAY add one sentence of market context from (B) with its source, clearly labelled as external context, if relevant.');
} else {
  parts.push('1. State the cooperative own price range (lowest to highest) and median, and how many entries / source types it is based on.');
  parts.push('2. Add brief market context from (B), attributing each contextual claim to its source (for example: according to FEWS NET ...).');
  parts.push('3. If outliers were flagged, note they should be reviewed before negotiation.');
  parts.push('4. End with the data confidence level (' + stats.data_confidence + ').');
}
parts.push('If (B) was empty, explicitly say that no external market context was retrieved.');
parts.push('Do not add a greeting or signature.');
parts.push('');
parts.push('Return ONLY a JSON object, no markdown fences:');
parts.push('{ "summary_text": "<the summary>", "data_confidence": "' + stats.data_confidence + '", "mentions_outliers": ' + (((stats.outliers || []).length > 0) ? 'true' : 'false') + ', "sources_cited": [] }');

return [{ json: {
  prompt: parts.join('\n'),
  retrieved_count: retrieved.length,
  retrieved_sources: retrieved.map((r) => r.meta.source || 'unknown')
}}];

const items = $input.all();
const item = items[0].json;
const stats = $('Compute price stats & outliers').all()[0].json;

let parsed;
try {
  const text = (item.text || item.output || '').replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
  parsed = JSON.parse(text);
} catch (e) {
  // Deterministic fallback built ONLY from real computed numbers - never invents a price
  let fallback;
  if (stats.insufficient_data) {
    fallback = 'There are only ' + stats.count + ' recent maize price entries for ' + stats.location_scope + ', which is not enough to give a reliable price summary. More entries are needed before negotiation.';
  } else {
    const s = stats.stats;
    fallback = 'Sample maize price entries for ' + stats.location_scope + ' range from NGN ' + s.min + ' to NGN ' + s.max + ' per bag, with a median of NGN ' + s.median + '. This is based on ' + stats.count + ' entries across ' + stats.source_list + '.' + (stats.outliers.length ? ' ' + stats.outliers.length + ' outlier price(s) were flagged and should be reviewed before negotiation.' : '') + ' Data confidence is ' + stats.data_confidence + ', given the number of entries and the source mix.';
  }
  parsed = { summary_text: fallback, data_confidence: stats.data_confidence, mentions_outliers: stats.outliers.length > 0, parse_error: e.message };
}

const summary_text = String(parsed.summary_text || '').trim();
const data_confidence = parsed.data_confidence || stats.data_confidence;
const outlier_count = (stats.outliers || []).length;
const source_list = stats.source_list || Object.keys(stats.source_breakdown || {}).join(', ');
const reason = 'data_confidence: ' + data_confidence + ' | entries: ' + stats.count + ' | sources: ' + (source_list || 'n/a') + ' | outliers_flagged: ' + outlier_count;

return [{ json: {
  summary_text: summary_text,
  data_confidence: data_confidence,
  count: stats.count,
  source_list: source_list,
  outlier_count: outlier_count,
  outliers: stats.outliers || [],
  location_scope: stats.location_scope,
  reason: reason,
  insufficient_data: !!stats.insufficient_data
}}];
